settings.custom_css:
/* input field css */
selector input::placeholder{
    opacity: 1;
}

selector input:focus::placeholder {
    opacity: 0;
    transition: all 0.4s;
}

/* textarea field css */
selector textarea::placeholder{
    opacity: 1;
}

selector textarea:focus::placeholder {
    opacity: 0;
    transition: all 0.4s;
}

selector .elementor-select-wrapper::before {
    color: #001689!important;
}

selector textarea {
    resize: none;
}

selector input {
    direction: rtl;
}

selector .elementor-field-type-acceptance {
    order:4;
}
